svg.script:
(function() {
  function show(id) { document.getElementById(id).setAttribute('display',''); }
  function hide(id) { document.getElementById(id).setAttribute('display','none'); }
  function closeAll() { hide('overlay'); hide('dlg-filter'); hide('dlg-settings'); hide('dlg-verify'); }

  // Overlay click closes dialogs
  document.getElementById('overlay').addEventListener('click', closeAll);

  // Open dialogs
  function openDlg(id) { show('overlay'); show(id); }
  ['btn-filter','btn-filter-t'].forEach(function(id){
    document.getElementById(id).addEventListener('click', function(){ openDlg('dlg-filter'); });
  });
  ['btn-settings','btn-settings-t'].forEach(function(id){
    document.getElementById(id).addEventListener('click', function(){ openDlg('dlg-settings'); });
  });
  ['btn-verify','btn-verify-t'].forEach(function(id){
    document.getElementById(id).addEventListener('click', function(){ openDlg('dlg-verify'); });
  });

  // Close buttons
  ['dlg-filter-close','filter-ok','filter-cancel'].forEach(function(id){
    document.getElementById(id).addEventListener('click', closeAll);
  });
  ['dlg-settings-close','settings-ok','settings-cancel'].forEach(function(id){
    document.getElementById(id).addEventListener('click', closeAll);
  });
  ['dlg-verify-close','verify-close-btn'].forEach(function(id){
    document.getElementById(id).addEventListener('click', closeAll);
  });

  // --- Filter: sort buttons ---
  var sortBtns = ['sort-new','sort-hot','sort-like'];
  sortBtns.forEach(function(id){
    document.getElementById(id).addEventListener('click', function(){
      sortBtns.forEach(function(sid){
        document.getElementById(sid).setAttribute('fill', sid===id ? '#0078d4' : '#f5f5f5');
        document.getElementById(sid).setAttribute('stroke', sid===id ? 'none' : '#c8c8c8');
        document.querySelector('#'+sid+' ~ text') // handled below
      });
    });
  });
  // simpler approach for sort text colors
  var sortData = [{r:'sort-new',t:'最新上传'},{r:'sort-hot',t:'最多观看'},{r:'sort-like',t:'最多点赞'}];
  sortData.forEach(function(d,i){
    document.getElementById(d.r).addEventListener('click', function(){
      sortData.forEach(function(od,oi){
        var active = oi===i;
        document.getElementById(od.r).setAttribute('fill', active ? '#0078d4' : '#f5f5f5');
      });
    });
  });

  // --- Filter: duration buttons ---
  var durData = ['dur-all','dur-short','dur-long'];
  durData.forEach(function(id,i){
    document.getElementById(id).addEventListener('click', function(){
      durData.forEach(function(oid,oi){
        document.getElementById(oid).setAttribute('fill', oi===i ? '#0078d4' : '#f5f5f5');
      });
    });
  });

  // --- Filter: tag toggle ---
  var tagSelected = {1:true,2:false,3:false,4:false,5:false,6:false,7:false,8:false};
  for(var n=1;n<=8;n++){
    (function(n){
      document.getElementById('tag-'+n+'-bg').addEventListener('click', function(){
        tagSelected[n] = !tagSelected[n];
        var on = tagSelected[n];
        document.getElementById('tag-'+n+'-bg').setAttribute('fill', on ? '#e3f2fd' : '#f5f5f5');
        document.getElementById('tag-'+n+'-bg').setAttribute('stroke', on ? '#1976d2' : '#c8c8c8');
        document.getElementById('tag-'+n+'-t').setAttribute('fill', on ? '#1976d2' : '#555');
      });
    })(n);
  }

  // --- Filter: broad match toggle ---
  var broadOn = true;
  document.getElementById('broad-bg').addEventListener('click', function(){
    broadOn = !broadOn;
    document.getElementById('broad-bg').setAttribute('fill', broadOn ? '#0078d4' : '#fff');
    document.getElementById('broad-bg').setAttribute('stroke', broadOn ? '#0078d4' : '#c8c8c8');
    document.getElementById('broad-check').setAttribute('fill', broadOn ? '#fff' : 'transparent');
  });

  // --- Filter: reset ---
  document.getElementById('filter-reset').addEventListener('click', function(){
    sortData.forEach(function(d,i){ document.getElementById(d.r).setAttribute('fill', i===0?'#0078d4':'#f5f5f5'); });
    durData.forEach(function(id,i){ document.getElementById(id).setAttribute('fill', i===0?'#0078d4':'#f5f5f5'); });
    for(var n=1;n<=8;n++){
      tagSelected[n] = n===1;
      document.getElementById('tag-'+n+'-bg').setAttribute('fill', n===1?'#e3f2fd':'#f5f5f5');
      document.getElementById('tag-'+n+'-bg').setAttribute('stroke', n===1?'#1976d2':'#c8c8c8');
      document.getElementById('tag-'+n+'-t').setAttribute('fill', n===1?'#1976d2':'#555');
    }
    broadOn=true;
    document.getElementById('broad-bg').setAttribute('fill','#0078d4');
    document.getElementById('broad-check').setAttribute('fill','#fff');
  });

  // --- Settings: theme toggle ---
  var darkMode = false;
  function setTheme(dark){
    darkMode = dark;
    document.getElementById('theme-light-bg').setAttribute('stroke', dark ? '#c8c8c8' : '#0078d4');
    document.getElementById('theme-light-bg').setAttribute('stroke-width', dark ? '1.5' : '2');
    document.getElementById('theme-light-dot').setAttribute('fill', dark ? 'transparent' : '#0078d4');
    document.getElementById('theme-dark-bg').setAttribute('stroke', dark ? '#0078d4' : '#c8c8c8');
    document.getElementById('theme-dark-bg').setAttribute('stroke-width', dark ? '2' : '1.5');
    document.getElementById('theme-dark-dot').setAttribute('fill', dark ? '#0078d4' : 'transparent');
  }
  document.getElementById('theme-light-bg').addEventListener('click', function(){ setTheme(false); });
  document.getElementById('theme-dark-bg').addEventListener('click', function(){ setTheme(true); });

  // --- Settings: compact mode toggle ---
  var compactOn = false;
  document.getElementById('compact-bg').addEventListener('click', function(){
    compactOn = !compactOn;
    document.getElementById('compact-bg').setAttribute('fill', compactOn ? '#0078d4' : '#c8c8c8');
    document.getElementById('compact-dot').setAttribute('cx', compactOn ? '341' : '327');
    document.getElementById('compact-label').textContent = compactOn ? '开启' : '关闭';
    document.getElementById('compact-label').setAttribute('fill', compactOn ? '#0078d4' : '#aaa');
  });

  // --- Settings: thumbnail cache toggle ---
  var thumbOn = true;
  document.getElementById('thumb-bg').addEventListener('click', function(){
    thumbOn = !thumbOn;
    document.getElementById('thumb-bg').setAttribute('fill', thumbOn ? '#0078d4' : '#c8c8c8');
    document.getElementById('thumb-dot').setAttribute('cx', thumbOn ? '341' : '327');
    document.getElementById('thumb-label').textContent = thumbOn ? '开启' : '关闭';
    document.getElementById('thumb-label').setAttribute('fill', thumbOn ? '#0078d4' : '#aaa');
  });

  // --- Settings: concurrent count ---
  var concurrent = 3;
  document.getElementById('concurrent-minus').addEventListener('click', function(){
    if(concurrent>1){ concurrent--; document.getElementById('concurrent-val').textContent=concurrent; }
  });
  document.getElementById('concurrent-plus').addEventListener('click', function(){
    if(concurrent<8){ concurrent++; document.getElementById('concurrent-val').textContent=concurrent; }
  });

  // --- Verify: CF checkbox ---
  var verified = false;
  document.getElementById('cf-box').addEventListener('click', function(){
    if(verified) return;
    document.getElementById('cf-check-bg').setAttribute('fill','#0078d4');
    document.getElementById('cf-check-bg').setAttribute('stroke','#0078d4');
    document.getElementById('cf-check-mark').setAttribute('fill','#fff');
    document.getElementById('cf-label').setAttribute('fill','#0078d4');
    document.getElementById('cf-status').textContent = '验证中...';
    setTimeout(function(){
      verified = true;
      document.getElementById('cf-status').textContent = '验证成功';
      document.getElementById('cf-status').setAttribute('fill','#43a047');
      document.getElementById('verify-result').textContent = 'Cookie 已保存，验证完成';
      document.getElementById('verify-result').setAttribute('fill','#43a047');
    }, 1200);
  });

  // --- Tabs ---
  var tabs = [{r:'tab-search',t:'tab-search-text'},{r:'tab-fav',t:'tab-fav-text'},{r:'tab-hist',t:'tab-hist-text'}];
  tabs.forEach(function(tab,i){
    function activate(){
      tabs.forEach(function(ot,oi){
        var active = oi===i;
        document.getElementById(ot.r).setAttribute('fill', active?'#fff':'#f0f0f0');
        document.getElementById(ot.r).setAttribute('stroke', active?'#999':'#d8d8d8');
        document.getElementById(ot.t).setAttribute('fill', active?'#111':'#777');
      });
    }
    document.getElementById(tab.r).addEventListener('click', activate);
    document.getElementById(tab.t).addEventListener('click', activate);
  });

  // --- List items ---
  var items=[1,2,3,4,5];
  items.forEach(function(n){
    function sel(){
      items.forEach(function(m){
        document.getElementById('item-bg-'+m).setAttribute('fill', m===n?'#e3f2fd':'#fff');
        document.getElementById('item-bar-'+m).setAttribute('fill', m===n?'#1976d2':'transparent');
      });
    }
    document.getElementById('item-bg-'+n).addEventListener('click',sel);
    var t=document.getElementById('item-title-'+n); if(t) t.addEventListener('click',sel);
  });

  // --- Video sources ---
  var srcs=[1,2,3];
  srcs.forEach(function(n){
    function sel(){
      srcs.forEach(function(m){
        document.getElementById('src-bg-'+m).setAttribute('fill', m===n?'#e3f2fd':'#fff');
        document.getElementById('src-bar-'+m).setAttribute('fill', m===n?'#1976d2':'transparent');
      });
    }
    document.getElementById('src-bg-'+n).addEventListener('click',sel);
  });

  // --- Progress ---
  var progressTimer=null, progressW=120, itemW=160;
  document.getElementById('btn-start').addEventListener('click', function(){
    if(progressTimer) return;
    progressTimer = setInterval(function(){
      progressW = Math.min(progressW+3, 292);
      itemW = Math.min(itemW+2, 292);
      document.getElementById('progress-bar').setAttribute('width', progressW);
      document.getElementById('item-progress').setAttribute('width', itemW);
      document.getElementById('item-pct').textContent = Math.round(itemW/292*100)+'%';
      if(progressW>=292){ clearInterval(progressTimer); progressTimer=null; }
    }, 50);
  });
  document.getElementById('btn-pause').addEventListener('click', function(){
    if(progressTimer){ clearInterval(progressTimer); progressTimer=null; }
  });

  // --- Search flash ---
  ['btn-search','btn-search-t'].forEach(function(id){
    document.getElementById(id).addEventListener('click', function(){
      var bgs = items.map(function(n){ return document.getElementById('item-bg-'+n); });
      var c=0, fl=setInterval(function(){
        bgs.forEach(function(el){ el.setAttribute('opacity', c%2===0?'0.3':'1'); });
        if(++c>=6){ clearInterval(fl); bgs.forEach(function(el){ el.setAttribute('opacity','1'); }); }
      }, 120);
    });
  });
})();
